mapper.select:
SELECT 
FROM t_committee_electronic_seal seal
JOIN sys_user custodian ON custodian.user_id = seal.custodian_user_id
WHERE seal.electronic_seal_id = #{sealId}
  AND seal.tenant_id = #{tenantId}

mapper.insert:
INSERT INTO t_committee_electronic_seal (
    tenant_id, seal_name, seal_type, provider_code, provider_seal_id,
    certificate_serial, valid_from, valid_until, status, custodian_user_id,
    committee_term_name, simulated, created_by_user_id
) VALUES (
    #{tenantId}, #{sealName}, #{sealType}, #{providerCode}, #{providerSealId},
    #{certificateSerial}, #{validFrom}, #{validUntil}, #{status}, #{custodianUserId},
    #{committeeTermName}, #{simulated}, #{createdByUserId}
)

mapper.update:
UPDATE t_committee_electronic_seal
SET status = 'INACTIVE',
    update_time = CURRENT_TIMESTAMP
WHERE electronic_seal_id = #{sealId}
  AND tenant_id = #{tenantId}
  AND status = 'ACTIVE'
